#include<bits/stdc++.h>
using namespace std;
int fa[500010],siz[500010],front[500010];
int find(int x)
{
    if(x==fa[x])
    {
        return x;
    }
    int fx=find(fa[x]);
    front[x]+=front[fa[x]];
    return fa[x]=fx;
}
int main()
{
    int t;
    scanf("%d",&t);
    for(int i=1;i<=500000;i++)
    {
        fa[i]=i;
        front[i]=0;
        siz[i]=1;
    }
    while(t--)
    {
        char op;
        int x,y;
        cin>>op;
        scanf("%d%d",&x,&y);
        int a=find(x),b=find(y);
        if(op=='M')
        {
            front[a]+=siz[b];
            fa[a]=b;
            siz[b]+=siz[a];
        }
        else
        {
            if(a!=b)
            {
                printf("-1\n");
            }
            else
            {
                printf("%d\n",abs(front[x]-front[y])-1);
            }
        }
    }
    return 0;
}
